customCss:
/* 全局样式重置 */
.resume-renderer {
  font-family: var(--typography-fontFamily-body);
  color: var(--colors-text-primary);
  line-height: var(--typography-lineHeight-normal);
  background-color: var(--colors-background);
}

/* 个人信息样式 */
.section-basic,
.section-basic-wrapper {
  text-align: center;
  margin-bottom: 30px;
}

.section-basic .section-content,
.section-basic-wrapper .section-content {
  display: flex;
  flex-direction: column;
  align-items: center;
}

/* 头像样式 */
.section-basic img,
.section-basic-wrapper img {
  width: 80px;
  height: 80px;
  border-radius: 50%;
  object-fit: cover;
  margin-bottom: 15px;
  border: 3px solid var(--colors-primary);
}

/* 姓名样式 */
.basic-name {
  font-size: 22px;
  font-weight: var(--typography-fontWeight-bold);
  color: var(--colors-text-primary);
  margin-bottom: 8px;
}

/* 职位样式 */
.basic-title {
  font-size: 16px;
  color: var(--colors-text-secondary);
  margin-bottom: 15px;
}

/* 联系信息样式 */
.contact-info {
  text-align: left;
  width: 100%;
}

.contact-item {
  display: flex;
  align-items: center;
  margin-bottom: 8px;
  font-size: 13px;
  color: var(--colors-text-secondary);
}

.contact-label {
  font-weight: var(--typography-fontWeight-medium);
  min-width: 45px;
  margin-right: 8px;
}

/* 模块标题样式 */
.section-education-title,
.section-skills-title,
.section-experience-title,
.section-projects-title,
.section-summary-title,
.section-education-wrapper .section-title,
.section-skills-wrapper .section-title,
.section-experience-wrapper .section-title,
.section-projects-wrapper .section-title,
.section-summary-wrapper .section-title {
  font-size: 16px !important;
  font-weight: var(--typography-fontWeight-bold) !important;
  color: var(--colors-background) !important;
  background-color: var(--colors-primary) !important;
  padding: 8px 15px !important;
  margin-bottom: 15px !important;
  text-align: center !important;
  border-radius: 0 !important;
  border: none !important;
  display: block !important;
}

/* 教育背景样式 */
.education-item {
  margin-bottom: 15px;
  padding-bottom: 12px;
  border-bottom: 1px solid var(--colors-border);
}

.education-item:last-child {
  border-bottom: none;
  margin-bottom: 0;
}

.education-period {
  font-size: 12px;
  color: var(--colors-text-secondary);
  margin-bottom: 4px;
}

.education-school {
  font-weight: var(--typography-fontWeight-bold);
  color: var(--colors-text-primary);
  margin-bottom: 3px;
  font-size: 14px;
}

.education-degree {
  color: var(--colors-text-secondary);
  font-size: 13px;
  margin-bottom: 3px;
}

.education-gpa {
  font-size: 12px;
  color: var(--colors-text-muted);
}

/* 工作经验样式 */
.experience-item {
  margin-bottom: 20px;
  padding-bottom: 15px;
  border-bottom: 1px solid var(--colors-border);
}

.experience-item:last-child {
  border-bottom: none;
  margin-bottom: 0;
}

.experience-header {
  margin-bottom: 8px;
}

.experience-period {
  font-size: 12px;
  color: var(--colors-text-secondary);
  margin-bottom: 4px;
}

.experience-company {
  font-weight: var(--typography-fontWeight-bold);
  color: var(--colors-text-primary);
  font-size: 14px;
  margin-bottom: 2px;
}

.experience-position {
  color: var(--colors-text-secondary);
  font-size: 13px;
  margin-bottom: 8px;
}

.experience-description {
  font-size: 13px;
  line-height: 1.5;
  color: var(--colors-text-primary);
}

.experience-description ul {
  margin: 0;
  padding-left: 16px;
}

.experience-description li {
  margin-bottom: 3px;
}

/* 技能样式 */
.skills-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.skill-item {
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 13px;
}

.skill-name {
  font-weight: var(--typography-fontWeight-medium);
  color: var(--colors-text-primary);
}

.skill-level {
  color: var(--colors-text-secondary);
  font-size: 12px;
}

/* 技能进度条样式 */
.skill-progress {
  margin-top: 4px;
  height: 4px;
  background-color: var(--colors-border);
  border-radius: 2px;
  overflow: hidden;
}

.skill-progress-bar {
  height: 100%;
  background-color: var(--colors-primary);
  transition: width 0.3s ease;
}

/* 自我评价样式 */
.summary-content {
  font-size: 13px;
  line-height: 1.6;
  color: var(--colors-text-primary);
  text-align: justify;
}

/* 响应式调整 */
@media (max-width: 768px) {
  .resume-columns {
    grid-template-columns: 1fr !important;
  }

  .column-left,
  .column-right {
    min-height: auto !important;
    padding: 20px !important;
  }

  .section-basic,
  .section-basic-wrapper {
    margin-bottom: 20px;
  }
}
